import{_ as e,a as d,b as a}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as l,o as r,c as o,a2 as i}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"إضافة قناة Cloudflare R2","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/upload/cloudflare-r2.md","filePath":"ar-SA/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),c={name:"ar-SA/upload/cloudflare-r2.md"};function n(u,t,h,b,s,m){return r(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="إضافة-قناة-cloudflare-r2" tabindex="-1">إضافة قناة Cloudflare R2 <a class="header-anchor" href="#إضافة-قناة-cloudflare-r2" aria-label="Permalink to &quot;إضافة قناة Cloudflare R2&quot;">​</a></h1><h2 id="متى-تكون-مناسبة؟" tabindex="-1">متى تكون مناسبة؟ <a class="header-anchor" href="#متى-تكون-مناسبة؟" aria-label="Permalink to &quot;متى تكون مناسبة؟&quot;">​</a></h2><p>استخدم Cloudflare R2 عندما:</p><ul><li>يكون موقع ImgBed منشورًا أصلًا على Cloudflare وتريد حفظ الملفات في R2 bucket ضمن الحساب نفسه.</li><li>لا ترغب في ضبط S3 endpoint و access key و secret key بشكل منفصل.</li><li>تريد أن تتم القراءة والكتابة عبر R2 binding في Worker أو Pages بأقل إعداد ممكن.</li></ul><p>باختصار:</p><p>لا تُنشأ قناة R2 يدويًا داخل لوحة إدارة ImgBed. يجب أولًا ربط R2 bucket بمشروع Cloudflare، ويجب أن يكون اسم متغير الربط بالضبط <code>img_r2</code>.</p><h2 id="ما-الذي-تحتاجه-قبل-البدء؟" tabindex="-1">ما الذي تحتاجه قبل البدء؟ <a class="header-anchor" href="#ما-الذي-تحتاجه-قبل-البدء؟" aria-label="Permalink to &quot;ما الذي تحتاجه قبل البدء؟&quot;">​</a></h2><ul><li>حساب Cloudflare.</li><li>R2 bucket موجود مسبقًا.</li><li>صلاحية إدارة مشروع Cloudflare الذي يعمل عليه ImgBed.</li></ul><h2 id="الإعداد-في-cloudflare" tabindex="-1">الإعداد في Cloudflare <a class="header-anchor" href="#الإعداد-في-cloudflare" aria-label="Permalink to &quot;الإعداد في Cloudflare&quot;">​</a></h2><h3 id="_1-أنشئ-r2-bucket" tabindex="-1">1. أنشئ R2 Bucket <a class="header-anchor" href="#_1-أنشئ-r2-bucket" aria-label="Permalink to &quot;1. أنشئ R2 Bucket&quot;">​</a></h3><ol><li>سجّل الدخول إلى Cloudflare Dashboard.</li><li>افتح <code>R2 Object Storage</code>.</li><li>اضغط Create bucket.</li><li>اختر اسمًا للـ bucket، مثل <code>imgbed</code>.</li></ol><p>سيتم حفظ الملفات المرفوعة داخل هذا الـ bucket.</p><p><img src="'+e+'" alt="إنشاء R2 bucket" loading="lazy"></p><h3 id="_2-اربط-الـ-bucket-بمشروع-imgbed" tabindex="-1">2. اربط الـ Bucket بمشروع ImgBed <a class="header-anchor" href="#_2-اربط-الـ-bucket-بمشروع-imgbed" aria-label="Permalink to &quot;2. اربط الـ Bucket بمشروع ImgBed&quot;">​</a></h3><p>اختر مكان الربط حسب نوع النشر:</p><table tabindex="0"><thead><tr><th>نوع النشر</th><th>مكان الربط</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>عند إضافة الربط، الحقول المهمة هي:</p><table tabindex="0"><thead><tr><th>الحقل</th><th>القيمة</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>اختر الـ bucket الذي أنشأته.</td></tr></tbody></table><p>يجب أن يكون اسم المتغير <code>img_r2</code> بالضبط. تعتمد عمليات الرفع والقراءة والحذف في R2 على اسم الربط هذا.</p><h3 id="_3-أعد-نشر-المشروع" tabindex="-1">3. أعد نشر المشروع <a class="header-anchor" href="#_3-أعد-نشر-المشروع" aria-label="Permalink to &quot;3. أعد نشر المشروع&quot;">​</a></h3><p>بعد حفظ الربط، أعد نشر ImgBed حتى يستطيع runtime الخاص بـ Worker أو Pages الوصول إلى <code>img_r2</code>.</p><h2 id="ماذا-سترى-في-imgbed؟" tabindex="-1">ماذا سترى في ImgBed؟ <a class="header-anchor" href="#ماذا-سترى-في-imgbed؟" aria-label="Permalink to &quot;ماذا سترى في ImgBed؟&quot;">​</a></h2><p>بعد توفر ربط R2، افتح:</p><ol><li>إعدادات النظام.</li><li>إعدادات الرفع.</li><li>قناة <code>Cloudflare R2</code>.</li></ol><p>ينشئ النظام قناة ثابتة واحدة تلقائيًا:</p><table tabindex="0"><thead><tr><th>الحقل</th><th>القيمة الثابتة</th></tr></thead><tbody><tr><td>اسم القناة</td><td><code>Cloudflare R2</code></td></tr><tr><td>نوع القناة</td><td><code>cfr2</code></td></tr><tr><td>وضع التخزين</td><td><code>binding</code></td></tr><tr><td>مصدر الإعداد</td><td>Environment binding</td></tr></tbody></table><p>هذه قناة ربط ثابتة. لا تحتاج إلى الضغط على Add Channel لإنشائها، ولا يمكن حذفها مثل القنوات العادية.</p><h2 id="الحقول-القابلة-للتعديل-في-لوحة-الإدارة" tabindex="-1">الحقول القابلة للتعديل في لوحة الإدارة <a class="header-anchor" href="#الحقول-القابلة-للتعديل-في-لوحة-الإدارة" aria-label="Permalink to &quot;الحقول القابلة للتعديل في لوحة الإدارة&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الحقل</th><th>وظيفته</th><th>مطلوب</th></tr></thead><tbody><tr><td>Enable channel</td><td>يحدد هل تشارك R2 في اختيار قناة الرفع.</td><td>نعم</td></tr><tr><td>Account ID</td><td>يستخدم فقط عند تفعيل حدود الحصة والحاجة إلى قراءة الاستخدام الرسمي لـ R2.</td><td>موصى به عند تفعيل الحصص</td></tr><tr><td>Bucket name</td><td>يستخدم فقط عند تفعيل حدود الحصة والحاجة إلى قراءة الاستخدام الرسمي لـ R2.</td><td>موصى به عند تفعيل الحصص</td></tr><tr><td>Quota limit</td><td>يحدد هل تُؤخذ سعة هذه القناة في الاعتبار عند اختيار قناة الرفع.</td><td>لا</td></tr><tr><td>Threshold</td><td>يوقف الكتابة إلى هذه القناة بعد بلوغ نسبة الاستخدام المحددة.</td><td>مطلوب عند تفعيل الحصص</td></tr></tbody></table><p>يمكن نسخ Account ID من لوحة معلومات الحساب في Cloudflare dashboard. املأه فقط إذا أردت من ImgBed قراءة استخدام حصة R2 وتطبيقه.</p><p><img src="'+d+'" alt="الحصول على Account ID" loading="lazy"></p><h2 id="خطوات-الإعداد" tabindex="-1">خطوات الإعداد <a class="header-anchor" href="#خطوات-الإعداد" aria-label="Permalink to &quot;خطوات الإعداد&quot;">​</a></h2><ol><li>أنشئ R2 bucket في Cloudflare.</li><li>افتح إعدادات Cloudflare الخاصة بمشروع ImgBed.</li><li>أضف R2 bucket binding.</li><li>اجعل <code>Variable name</code> مساويًا لـ <code>img_r2</code>.</li><li>اختر R2 bucket الذي أنشأته.</li><li>احفظ الربط وأعد نشر ImgBed.</li><li>ارجع إلى ImgBed -&gt; System Settings -&gt; Upload Settings.</li><li>تأكد من ظهور قناة <code>Cloudflare R2</code> وأنها مفعلة.</li></ol><p>إذا أردت أن تشارك R2 في اختيار قناة الرفع حسب السعة، فعّل quota limit ثم أدخل Account ID واسم الـ bucket وحد الحصة والـ threshold قبل الحفظ.</p><p><img src="'+a+'" alt="ضبط حدود الحصة" loading="lazy"></p><h2 id="كيف-تتحقق؟" tabindex="-1">كيف تتحقق؟ <a class="header-anchor" href="#كيف-تتحقق؟" aria-label="Permalink to &quot;كيف تتحقق؟&quot;">​</a></h2><ul><li>تظهر قناة <code>Cloudflare R2</code> الثابتة في إعدادات الرفع.</li><li>تظهر بطاقة القناة على أنها مفعلة.</li><li>ينجح رفع ملف صغير، ويفتح الرابط الناتج بشكل طبيعي.</li><li>إذا أعاد فتح الملف رسالة <code>R2 database binding is not configured</code> فهذا يعني أن runtime لم يستلم الربط <code>img_r2</code>. تحقق من اسم الربط في Cloudflare وأعد نشر المشروع.</li></ul>',37)])])}const k=l(c,[["render",n]]);export{f as __pageData,k as default};
